use std::collections::HashMap;

#[derive(Debug, PartialEq)]
enum ScanResult {
    Safe,
    VirusDetected(String),
}

struct FileUploader {
    scanner: Box<dyn VirusScanner>, 
}

impl FileUploader {
    fn new(scanner: Box<dyn VirusScanner>) -> Self {
        Self { scanner }
    }

    fn handle_upload(&self, file_name: &str, content: Vec<u8>) -> Result<(), String> {
        match self.scanner.scan_file(file_name, &content) {
            ScanResult::Safe => Ok(()),
            ScanResult::VirusDetected(reason) => Err(format!("Upload blocked due to virus: {}", reason)),
        }
    }
}

trait VirusScanner {
    fn scan_file(&self, file_name: &str, content: &[u8]) -> ScanResult;
}

struct MockScanner;

impl VirusScanner for MockScanner {
    fn scan_file(&self, _file_name: &str, _content: &[u8]) -> ScanResult {
        ScanResult::Safe
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use mockall;

    mock! {
        trait MockVirusScanner {}
        fn scan_file(&self, file_name: &str, content: &[u8]) -> ScanResult;
    }

    #[test]
    fn test_upload_when_scan_is_successful() {
        let mut mock_scanner = MockVirusScanner::new();
        mock_scanner.expect_scan_file()
            .with("test.bin", &vec![1, 2, 3])
            .return_const(ScanResult::Safe);

        let uploader = FileUploader::new(Box::new(mock_scanner));
        let result = uploader.handle_upload("test.bin", vec![1, 2, 3]);
        assert!(result.is_ok());
    }

    #[test]
    fn test_upload_when_virus_detected() {
        let mut mock_scanner = MockVirusScanner::new();
        mock_scanner.expect_scan_file()
            .with("bad.exe", &vec![0xFF])
            .return_const(ScanResult::VirusDetected("Malware signature match".to_string()));

        let uploader = FileUploader::new(Box::new(mock_scanner));
        let result = uploader.handle_upload("bad.exe", vec![0xFF]);
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("Malware signature match"));
    }
}

use std::collections::HashMap;
use std::sync::Arc;

struct BinaryDiffer {
    dependencies: Arc<dyn DiffService + Send + Sync>,
}

impl BinaryDiffer {
    fn new(deps: Arc<dyn DiffService + Send + Sync>) -> Self {
        Self { dependencies: deps }
    }

    fn calculate_diff(&self, image1: &[u8], image2: &[u8]) -> Result<Vec<String>, Box<dyn std::error::Error>> {
        let diff_result = self.dependencies.check_for_changes(image1, image2);
        if let Some(patches) = diff_result {
            Ok(patches)
        } else {
            Err("No differences found.".into())}
    }
}

trait DiffService {
    fn check_for_changes(&self, img1: &[u8], img2: &[u8]) -> Option<Vec<String>>;
}

struct MockDiffService;

impl DiffService for MockDiffService {
    fn check_for_changes(&self, img1: &[u8], img2: &[u8]) -> Option<Vec<String>> {
        if img1.len() < 10 || img2.len() < 10 {
            return None;
        }
        let mut patches = vec![String::from("Patch A applied"), String::from("Patch B applied")];
        Some(patches)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mock_service = Arc::new(MockDiffService);
    let differ = BinaryDiffer::new(mock_service);

    let image_a = vec![0; 12];
    let image_b = vec![1; 12];

    match differ.calculate_diff(&image_a, &image_b) {
        Ok(patches) => {
            println!("Successfully found {} patches.", patches.len());
        }
        Err(e) => {
            eprintln!("Error calculating diff: {}", e);
        }
    }
    Ok(())
}
